class AuthHandler:
    """JWT-based authentication handler with async support."""
    def __init__(self, secret_key):
        self.secret_key = secret_key

from functools import wraps

def require_auth(handler: AuthHandler):
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            return f(*args, **kwargs)
        return decorated
    return decorator

