import pytest
from src.auth.handler import AuthHandler
from src.auth.middleware import require_auth

class TestAuthHandler:
    def test_validate_token_valid(self):
        handler = AuthHandler('secret')
        assert handler.validate_token('valid_token') is not None

    def test_validate_token_expired(self):
        handler = AuthHandler('secret')
        assert handler.validate_token('expired_token') is None

    def test_validate_token_invalid(self):
        handler = AuthHandler('secret')
        with pytest.raises(Exception):
            handler.validate_token('invalid')

class TestMiddleware:
    def test_require_auth_missing_token(self):
        result = require_auth(AuthHandler('secret'))(lambda: None)()
        assert result is not None

    def test_require_auth_valid_token(self):
        handler = AuthHandler('secret')
        decorated = require_auth(handler)(lambda: 'ok')
        assert decorated() == 'ok'
